const payload = $json.body ?? $json;
const { sessionId, studentId, currentStreak = 0, currentCoins = 0 } = payload;

if (!sessionId || !studentId) {
  throw new Error('sessionId and studentId are required');
}

const store = $getWorkflowStaticData('global');
store.rewardedSessionIds ??= {};

if (store.rewardedSessionIds[sessionId]) {
  return [{ json: { sessionId, studentId, rewardApplied: false, reason: 'duplicate_session', ...store.rewardedSessionIds[sessionId] } }];
}

const reward = {
  streak: Number(currentStreak) + 1,
  coins: Number(currentCoins) + 50,
  coinsAwarded: 50
};

store.rewardedSessionIds[sessionId] = reward;

return [{ json: { sessionId, studentId, rewardApplied: true, ...reward } }];
